<?php
 namespace WPAICG\Vector\Providers\Pinecone\Methods; use WPAICG\Vector\Providers\AIPKit_Vector_Pinecone_Strategy; use WP_Error; if (!defined('ABSPATH')) { exit; } function delete_vectors_logic(AIPKit_Vector_Pinecone_Strategy $strategyInstance, string $index_name, array $vector_ids): bool|WP_Error { $index_description = get_index_overview_logic($strategyInstance, $index_name); if (is_wp_error($index_description)) return $index_description; $host = $index_description['host'] ?? null; if (empty($host)) return new WP_Error('missing_host_pinecone_delete_vectors', __('Index host not found for delete vectors.', 'gpt3-ai-content-generator')); $path = '/vectors/delete'; if (isset($vector_ids['ids']) && is_array($vector_ids['ids'])) { $body = ['ids' => array_values($vector_ids['ids'])]; } elseif (isset($vector_ids['filter']) && is_array($vector_ids['filter'])) { $body = ['filter' => $vector_ids['filter']]; } elseif (!empty($vector_ids['deleteAll'])) { $body = ['deleteAll' => true]; } else { $body = ['ids' => array_values($vector_ids)]; } if (isset($vector_ids['namespace']) && is_string($vector_ids['namespace']) && $vector_ids['namespace'] !== '') { $body['namespace'] = $vector_ids['namespace']; } $response = _request_logic($strategyInstance, 'POST', $path, $body, 'https://' . $host); if (is_wp_error($response)) return $response; return empty($response); } 